from dataclasses import dataclass, field
from typing import Callable

@dataclass
class RoleDefinition:
    name: str
    responsibility: str
    does_not: list[str]
    model: str
    system_prompt: str

# Role registry: single source of truth for all agent roles
ROLE_REGISTRY: dict[str, RoleDefinition] = {}

def register_role(role: RoleDefinition) -> RoleDefinition:
    ROLE_REGISTRY[role.name] = role
    return role

@register_role
def _() -> RoleDefinition:
    return RoleDefinition(
        name="classifier",
        responsibility="Classify support tickets into four categories.",
        does_not=["generate responses", "retrieve external data"],
        model="claude-haiku-4-5-20251001",
        system_prompt=(
            "You are a support ticket classification specialist.\n"
            "Classify tickets into: technical, billing, account, other.\n"
            "You do NOT: generate responses, retrieve external data."
        ),
    )

@register_role
def _2() -> RoleDefinition:
    return RoleDefinition(
        name="summariser",
        responsibility="Condense documents into a summary and key points.",
        does_not=["classify", "respond to users", "retrieve new data"],
        model="claude-haiku-4-5-20251001",
        system_prompt=(
            "You are a document summarisation specialist.\n"
            "Output: summary (max 3 sentences) and key_points (3-5 items).\n"
            "You do NOT: classify, respond to users, retrieve new data."
        ),
    )

# Now any graph can look up a role without hardcoding system prompts
def make_node(role_name: str):
    role = ROLE_REGISTRY[role_name]
    def node(state: dict) -> dict:
        from langchain_anthropic import ChatAnthropic
        llm = ChatAnthropic(model=role.model)
        result = llm.invoke([
            {"role": "system", "content": role.system_prompt},
            {"role": "user", "content": str(state.get("input", ""))}
        ])
        return {"output": result.content}
    node.__name__ = role_name
    return node
